import{_ as t,o as a,c as n,ag as i}from"./chunks/framework.ePeAWSvT.js";const r="/assets/monitor-maintain-index.ChdHhtgi.png",p=JSON.parse('{"title":"Maintain Index","description":"","frontmatter":{},"headers":[],"relativePath":"guide/monitor-maintain-index.md","filePath":"guide/monitor-maintain-index.md"}'),o={name:"guide/monitor-maintain-index.md"};function s(l,e,d,h,c,g){return a(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="maintain-index" tabindex="-1">Maintain Index <a class="header-anchor" href="#maintain-index" aria-label="Permalink to &quot;Maintain Index&quot;">​</a></h1><p>The Maintain Index page provides tools for managing the entity search index used by the platform. The Maintain Index feature catalogs all of the Keys that associate records between systems. An Index card will be created for each Schema Property being synced within your Data Hubs upon the first sync. Each card will display the source System ID and primary Key for that record.</p><p><img src="'+r+'" alt="Maintain Index Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Index Management</strong> — Rebuild or update the entity search index</li><li><strong>Entity Search</strong> — Search for specific entities by type and key values</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>You can manually edit existing index records, as well as add new index records; however, it is strongly advised that only those with advanced knowledge perform this task. Modifying the index data can have severe outcomes on your integrations.</p></div><div class="info custom-block"><p class="custom-block-title">Advanced Tool</p><p>Indexes are the primary way Central knows how to map the data records between systems (e.g. Customer ID, Purchase Order numbers), so it is imperative that this data is consistent and accurate. All Indexes are displayed in and/or manually added to the Maintain Index feature.</p></div><h2 id="searching-the-index" tabindex="-1">Searching the Index <a class="header-anchor" href="#searching-the-index" aria-label="Permalink to &quot;Searching the Index&quot;">​</a></h2><p>When searching the Index, users can search by <strong>Key</strong>, <strong>Identifier</strong>, or <strong>Property</strong>.</p><ul><li><strong>Key</strong> — Enter a Search Value that references any key data found in that Index. For example, if you search the Customer Schemas for a value of <em>1234</em>, it will return any indexes that contain <em>1234</em> in their Source System IDs.</li><li><strong>Identifier</strong> — Identifiers are specific keywords that depend upon the selected Schema. These recognized search fields will be displayed once a Schema has been selected. For example, if you select a Customer Schema, Identifiers might include <em>FullName</em>, <em>Email</em>, etc.</li><li><strong>Property</strong> — Any other properties defined on the data model can be used in the search.</li></ul><h2 id="manage-the-index" tabindex="-1">Manage the Index <a class="header-anchor" href="#manage-the-index" aria-label="Permalink to &quot;Manage the Index&quot;">​</a></h2><ol><li>Select <strong>Monitor</strong> &gt; <strong>Maintain Index</strong>.</li><li>Then, use the table below to determine the next steps.</li></ol><h3 id="view-indexes" tabindex="-1">View Indexes <a class="header-anchor" href="#view-indexes" aria-label="Permalink to &quot;View Indexes&quot;">​</a></h3><ol><li>Select a <strong>Search Type</strong> and a <strong>Schema</strong>.</li><li>Enter a <strong>Search Value</strong>.</li><li>As needed, toggle <strong>Exact Match</strong> ON or OFF.</li><li>Select <strong>Search</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>Identifiers are keywords that can be used when searching by Identifier. The applicable Identifiers will be shown below the Search Type once a Schema has been selected.</p></div><h3 id="add-an-index" tabindex="-1">Add an Index <a class="header-anchor" href="#add-an-index" aria-label="Permalink to &quot;Add an Index&quot;">​</a></h3><ol><li>Select a <strong>Schema</strong>.</li><li>Select <strong>+Add</strong>.</li><li>Select the <strong>Primary Keys</strong> tab.</li><li>Select the <strong>System Source</strong>, enter the <strong>System Source ID</strong>, and select <strong>Add</strong>. Repeat this step until all necessary Primary Keys are added.</li><li>Select the <strong>Fields</strong> tab and enter all applicable data (see note below).</li><li>When finished, select <strong>Save</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Only keys and a single Identifier per grouping are required when manually adding an index. However, it is strongly advised to enter at least a <strong>Name</strong> to identify the Index card, as well as additional attributes within the Fields tab.</p></div><h3 id="edit-the-primary-keys-and-or-fields-for-an-index" tabindex="-1">Edit the Primary Keys and/or Fields for an Index <a class="header-anchor" href="#edit-the-primary-keys-and-or-fields-for-an-index" aria-label="Permalink to &quot;Edit the Primary Keys and/or Fields for an Index&quot;">​</a></h3><ol><li>Follow the <em>View Indexes</em> steps to find the appropriate Index.</li><li>In the appropriate Index card, select the <strong>menu</strong> icon &gt; <strong>Edit</strong>.</li><li>Select the <strong>Primary Keys</strong> tab. <ul><li>To add a Primary Key, select the <strong>System Source</strong>, enter the <strong>System Source ID</strong>, and select <strong>Add</strong>.</li><li>To delete a Primary Key, select the <strong>delete</strong> icon in the appropriate row.</li></ul></li><li>Select the <strong>Fields</strong> tab; then, edit any of the data as needed.</li><li>When finished, select <strong>Save</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>To discard current edits and start over, select <strong>Reset</strong>; or to discard current edits and exit Edit Mode, select <strong>Close</strong>.</p></div><h3 id="delete-an-index" tabindex="-1">Delete an Index <a class="header-anchor" href="#delete-an-index" aria-label="Permalink to &quot;Delete an Index&quot;">​</a></h3><ol><li>Follow the <em>View Indexes</em> steps to find the appropriate Index.</li><li>In the appropriate Index card, select the <strong>menu</strong> icon &gt; <strong>Delete</strong>.</li><li>Select <strong>OK</strong> to confirm.</li></ol><h3 id="view-record-history-for-an-index" tabindex="-1">View Record History for an Index <a class="header-anchor" href="#view-record-history-for-an-index" aria-label="Permalink to &quot;View Record History for an Index&quot;">​</a></h3><ol><li>Follow the <em>View Indexes</em> steps to find the appropriate Index.</li><li>In the appropriate Index card, select the <strong>menu</strong> icon &gt; <strong>View Record History</strong>. The Record History will open in a new browser tab.</li><li>From here, you can select <strong>Actions</strong> &gt; <strong>Re-Run Message</strong> or <strong>Actions</strong> &gt; <strong>View Details</strong>; see the <a href="./monitor-messages.html">Messages</a> page for additional information.</li></ol><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./monitor-messages.html">Messages</a> — Inspect individual integration messages</li><li><a href="./monitor-error-logs.html">Error Logs</a> — Investigate processing errors</li><li><a href="./monitor-dashboard.html">Monitor Dashboard</a> — View platform health at a glance</li><li><a href="./datahub-key-scraping.html">Key Scraping</a> — Configure how primary keys are indexed</li></ul>',27)])])}const u=t(o,[["render",s]]);export{p as __pageData,u as default};
